<?php
if (!function_exists('hr_t')) {
  function hr_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('hr_h')) {
  function hr_h($key, $fallback = '') { return htmlspecialchars((string) hr_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('hr_js')) {
  function hr_js($key, $fallback = '') { return json_encode(hr_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
if (session_status() === PHP_SESSION_NONE) session_start();
include "../../inc/config.php";
session_check_json();
function otr_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function otr_label($s){$m=array('DRAFT'=>'warning','REQUESTED'=>'info','APPROVED'=>'success','REJECTED'=>'danger','POSTED'=>'primary','CANCELLED'=>'default');$c=isset($m[$s])?$m[$s]:'default';return '<span class="label label-'.$c.'">'.otr_h($s).'</span>';}
function otr_filters(){return array('from'=>isset($_POST['tgl_awal'])&&$_POST['tgl_awal']!==''?$_POST['tgl_awal']:date('Y-m-01'),'to'=>isset($_POST['tgl_akhir'])&&$_POST['tgl_akhir']!==''?$_POST['tgl_akhir']:date('Y-m-t'),'employee_id'=>isset($_POST['employee_id'])?trim($_POST['employee_id']):'','department_code'=>isset($_POST['department_code'])?trim($_POST['department_code']):'','cost_center_code'=>isset($_POST['cost_center_code'])?trim($_POST['cost_center_code']):'','overtime_type'=>isset($_POST['overtime_type'])?trim($_POST['overtime_type']):'','overtime_status'=>isset($_POST['overtime_status'])?trim($_POST['overtime_status']):'','request_source'=>isset($_POST['request_source'])?trim($_POST['request_source']):'','impact_type'=>isset($_POST['impact_type'])?trim($_POST['impact_type']):'','keyword'=>isset($_POST['keyword'])?trim($_POST['keyword']):'');}
function otr_where($f,&$p){$w=" WHERE ot.overtime_date BETWEEN ? AND ? ";array_push($p,$f['from'],$f['to']);if($f['employee_id']!==''){$w.=" AND ot.employee_id=? ";$p[]=(int)$f['employee_id'];}foreach(array('department_code','cost_center_code','overtime_type','overtime_status','request_source') as $k){if($f[$k]!==''){$w.=" AND ot.$k=? ";$p[]=$f[$k];}}if($f['impact_type']==='PAYABLE')$w.=" AND ot.payable_hours>0 ";elseif($f['impact_type']==='UNAPPROVED')$w.=" AND ot.overtime_status IN ('DRAFT','REQUESTED') ";elseif($f['impact_type']==='REJECTED')$w.=" AND ot.overtime_status='REJECTED' ";elseif($f['impact_type']==='PAYROLL_POSTED')$w.=" AND ot.overtime_status='POSTED' ";elseif($f['impact_type']==='NO_ATTENDANCE_REF')$w.=" AND ot.attendance_id IS NULL ";if($f['keyword']!==''){$kw='%'.$f['keyword'].'%';$w.=" AND (ot.overtime_no LIKE ? OR ot.employee_no LIKE ? OR e.full_name LIKE ? OR ot.overtime_reason LIKE ? OR ot.sap_reference LIKE ? OR d.nm_dept LIKE ?) ";for($i=0;$i<6;$i++)$p[]=$kw;}return $w;}
$draw=isset($_POST['draw'])?(int)$_POST['draw']:1;$start=isset($_POST['start'])?max(0,(int)$_POST['start']):0;$length=isset($_POST['length'])?(int)$_POST['length']:25;if($length<=0||$length>500)$length=25;
$f=otr_filters();$p=array();$w=otr_where($f,$p);
$base=" FROM erp_overtime ot JOIN erp_employee_master e ON e.id=ot.employee_id LEFT JOIN dept d ON d.kd_dept=ot.department_code LEFT JOIN erp_cost_center cc ON cc.cost_center_code=ot.cost_center_code LEFT JOIN erp_attendance a ON a.id=ot.attendance_id ";
$kpi=$db->fetch("SELECT COUNT(*) total,SUM(ot.overtime_status='REQUESTED') requested_count,SUM(ot.overtime_status='APPROVED') approved_count,SUM(ot.overtime_status='POSTED') posted_count,SUM(ot.overtime_status='REJECTED') rejected_count,ROUND(SUM(ot.requested_hours),2) requested_hours,ROUND(SUM(ot.approved_hours),2) approved_hours,ROUND(SUM(ot.payable_hours),2) payable_hours,ROUND(SUM(ot.estimated_amount),2) amount $base $w",$p);
$cnt=$db->fetch("SELECT COUNT(*) jml $base $w",$p);$total=$cnt?(int)$cnt->jml:0;
$orderMap=array(2=>'ot.overtime_no',3=>'ot.overtime_date',4=>'e.employee_no',5=>'d.kd_dept',6=>'ot.cost_center_code',7=>'ot.overtime_type',8=>'ot.requested_hours',9=>'ot.payable_hours',10=>'ot.estimated_amount',11=>'ot.overtime_status',12=>'ot.updated_at');$orderBy='ot.overtime_date DESC,ot.overtime_no DESC';
if(isset($_POST['order'][0]['column'])){$col=(int)$_POST['order'][0]['column'];$dir=(isset($_POST['order'][0]['dir'])&&strtolower($_POST['order'][0]['dir'])==='desc')?'DESC':'ASC';if(isset($orderMap[$col]))$orderBy=$orderMap[$col].' '.$dir;}
$rows=$db->query("SELECT ot.*,e.full_name,e.employee_group,d.nm_dept,cc.cost_center_name,a.attendance_date,a.overtime_hours attendance_ot $base $w ORDER BY $orderBy LIMIT $start,$length",$p);
$data=array();$no=$start+1;foreach($rows as $r){$ref=$r->attendance_no?($r->attendance_no.' / '.($r->attendance_ot?:'0.00').'h'):'Manual';$variance=(float)$r->requested_hours-(float)$r->payable_hours;$data[]=array($no++,'<button class="btn btn-info btn-xs btn-otr-detail" data-id="'.(int)$r->id.'"><i class="fa fa-eye"></i></button>','<strong>'.otr_h($r->overtime_no).'</strong><br><small>'.otr_h($r->sap_reference?:'-').'</small>',otr_h($r->overtime_date),'<strong>'.otr_h($r->employee_no).'</strong><br><small>'.otr_h($r->full_name).' / '.otr_h($r->employee_group).'</small>','<strong>'.otr_h($r->department_code?:'-').'</strong><br><small>'.otr_h($r->nm_dept?:'-').'</small>','<strong>'.otr_h($r->cost_center_code?:'-').'</strong><br><small>'.otr_h($r->cost_center_name?:'-').'</small>','<strong>'.otr_h($r->overtime_type).'</strong><br><small>'.otr_h($r->request_source.' / '.$ref).'</small>',otr_h($r->planned_start?substr($r->planned_start,11,5):'-').' - '.otr_h($r->planned_end?substr($r->planned_end,11,5):'-').'<br><small>Actual '.otr_h($r->actual_start?substr($r->actual_start,11,5):'-').' - '.otr_h($r->actual_end?substr($r->actual_end,11,5):'-').'</small>','Req '.otr_h($r->requested_hours).' | App '.otr_h($r->approved_hours).'<br><small>Pay '.otr_h($r->payable_hours).' | Var '.number_format($variance,2).'</small>','<strong>'.number_format((float)$r->estimated_amount,2).'</strong><br><small>'.number_format((float)$r->hourly_rate,2).' x '.otr_h($r->rate_multiplier).'</small>',otr_label($r->overtime_status),otr_h($r->updated_by?:$r->created_by?:'-').'<br><small>'.otr_h($r->updated_at?:$r->created_at).'</small>');}
$approvalRate=($kpi&&$kpi->total>0)?round((($kpi->approved_count+$kpi->posted_count)/$kpi->total)*100,2):0;
header('Content-Type: application/json; charset=utf-8');echo json_encode(array('draw'=>$draw,'recordsTotal'=>$total,'recordsFiltered'=>$total,'data'=>$data,'kpi'=>array('total'=>$kpi?(int)$kpi->total:0,'requested'=>$kpi?(int)$kpi->requested_count:0,'approved'=>$kpi?(int)$kpi->approved_count:0,'posted'=>$kpi?(int)$kpi->posted_count:0,'rejected'=>$kpi?(int)$kpi->rejected_count:0,'requested_hours'=>$kpi?$kpi->requested_hours:0,'payable_hours'=>$kpi?$kpi->payable_hours:0,'amount'=>$kpi?$kpi->amount:0,'approval_rate'=>$approvalRate)));
?>
